document.addEventListener("DOMContentLoaded",function(){const e=document.querySelector(".photo-track");if(!e)return;function t(){const t=window.innerWidth,i=window.innerHeight,n=Math.floor(t/8),s=Math.floor(t/4),o=e.querySelectorAll(".photo-item"),a=o.length,r=(n+s)/2,c=Math.floor(t/r),l=Math.ceil(a/c),d=Math.max(i*1.5,l*s);e.style.height=`${d}px`,o.forEach(e=>{const t=n+Math.random()*(s-n),o=.7+Math.random()*.7;e.style.width=`${t}px`,e.style.height=`${Math.floor(t*o)}px`,e.style.transform="none"})}t();let n;window.addEventListener("resize",()=>{clearTimeout(n),n=setTimeout(t,200)})})